<script setup>import{onMounted,ref}from'vue';import PageActions from'../../../components/admin/PageActions.vue';import WorkSummaryCards from'../../../components/admin/WorkSummaryCards.vue';import{reportApi}from'../../../lib/reportApi.js';import{taskApi}from'../../../lib/taskApi.js';const tasks=ref([]),taskId=ref(''),summary=ref(null),error=ref('');async function init(){try{tasks.value=(await taskApi.list(0,100)).items||[]}catch(e){error.value=e.message}}async function search(){try{summary.value=await reportApi.tasks({taskId:taskId.value})}catch(e){error.value=e.message}}onMounted(init)</script>
<template><section class="admin-page"><PageActions title="任务统计" description="同时展示累计工作量与当前有效结果。"/><div class="business-card"><form class="business-inline" @submit.prevent="search"><select v-model="taskId" required><option value="">选择任务</option><option v-for="t in tasks" :key="t.id" :value="t.id">{{t.name}}</option></select><button class="button-primary">查询</button></form><p v-if="error" class="business-error">{{error}}</p><WorkSummaryCards v-if="summary" :summary="summary"/></div></section></template>
